297	137	ai	I'll create a comprehensive Binary Search Tree class with all the essential operations. Here's my approach:\n\n1. **Node Structure**: Simple node class with value, left, and right pointers\n2. **Core Operations**: Insert, search, delete with proper BST property maintenance\n3. **Traversal Methods**: In-order, pre-order, post-order, and level-order\n4. **Helper Methods**: Find minimum, maximum, and tree validation\n\n```python\nfrom collections import deque\nfrom typing import Optional, List, Any\n\nclass TreeNode:\n    """Node class for Binary Search Tree"""\n    def __init__(self, val: int):\n        self.val = val\n        self.left: Optional['TreeNode'] = None\n        self.right: Optional['TreeNode'] = None\n\nclass BinarySearchTree:\n    """\n    Binary Search Tree implementation with basic operations.\n    \n    Maintains the BST property: left subtree < node < right subtree\n    """\n    \n    def __init__(self):\n        self.root: Optional[TreeNode] = None\n    \n    def insert(self, val: int) -> None:\n        """\n        Insert a value into the BST.\n        \n        Args:\n            val: Integer value to insert\n        """\n        self.root = self._insert_recursive(self.root, val)\n    \n    def _insert_recursive(self, node: Optional[TreeNode], val: int) -> TreeNode:\n        """Helper method for recursive insertion"""\n        # Base case: create new node\n        if node is None:\n            return TreeNode(val)\n        \n        # Insert in appropriate subtree\n        if val < node.val:\n            node.left = self._insert_recursive(node.left, val)\n        elif val > node.val:\n            node.right = self._insert_recursive(node.right, val)\n        # If val == node.val, we don't insert duplicates\n        \n        return node\n    \n    def search(self, val: int) -> bool:\n        """\n        Search for a value in the BST.\n        \n        Args:\n            val: Value to search for\n            \n        Returns:\n            True if value exists, False otherwise\n        """\n        return self._search_recursive(self.root, val)\n    \n    def _search_recursive(self, node: Optional[TreeNode], val: int) -> bool:\n        """Helper method for recursive search"""\n        if node is None:\n            return False\n        \n        if val == node.val:\n            return True\n        elif val < node.val:\n            return self._search_recursive(node.left, val)\n        else:\n            return self._search_recursive(node.right, val)\n    \n    def delete(self, val: int) -> None:\n        """\n        Delete a value from the BST.\n        \n        Args:\n            val: Value to delete\n        """\n        self.root = self._delete_recursive(self.root, val)\n    \n    def _delete_recursive(self, node: Optional[TreeNode], val: int) -> Optional[TreeNode]:\n        """Helper method for recursive deletion"""\n        if node is None:\n            return None\n        \n        # Find the node to delete\n        if val < node.val:\n            node.left = self._delete_recursive(node.left, val)\n        elif val > node.val:\n            node.right = self._delete_recursive(node.right, val)\n        else:\n            # Node to delete found\n            # Case 1: Node has no children (leaf)\n            if node.left is None and node.right is None:\n                return None\n            \n            # Case 2: Node has one child\n            if node.left is None:\n                return node.right\n            if node.right is None:\n                return node.left\n            \n            # Case 3: Node has two children\n            # Find inorder successor (smallest value in right subtree)\n            successor = self._find_min(node.right)\n            node.val = successor.val\n            # Delete the successor\n            node.right = self._delete_recursive(node.right, successor.val)\n        \n        return node\n    \n    def _find_min(self, node: TreeNode) -> TreeNode:\n        """Find the minimum value node in a subtree"""\n        while node.left is not None:\n            node = node.left\n        return node\n    \n    def find_min(self) -> Optional[int]:\n        """Find minimum value in the entire tree"""\n        if self.root is None:\n            return None\n        return self._find_min(self.root).val\n    \n    def find_max(self) -> Optional[int]:\n        """Find maximum value in the entire tree"""\n        if self.root is None:\n            return None\n        \n        node = self.root\n        while node.right is not None:\n            node = node.right\n        return node.val\n    \n    # Traversal Methods\n    \n    def inorder_traversal(self) -> List[int]:\n        """\n        Perform inorder traversal (Left -> Root -> Right).\n        Returns values in sorted order for BST.\n        """\n        result = []\n        self._inorder_recursive(self.root, result)\n        return result\n    \n    def _inorder_recursive(self, node: Optional[TreeNode], result: List[int]) -> None:\n        """Helper for inorder traversal"""\n        if node is not None:\n            self._inorder_recursive(node.left, result)\n            result.append(node.val)\n            self._inorder_recursive(node.right, result)\n    \n    def preorder_traversal(self) -> List[int]:\n        """Perform preorder traversal (Root -> Left -> Right)"""\n        result = []\n        self._preorder_recursive(self.root, result)\n        return result\n    \n    def _preorder_recursive(self, node: Optional[TreeNode], result: List[int]) -> None:\n        """Helper for preorder traversal"""\n        if node is not None:\n            result.append(node.val)\n            self._preorder_recursive(node.left, result)\n            self._preorder_recursive(node.right, result)\n    \n    def postorder_traversal(self) -> List[int]:\n        """Perform postorder traversal (Left -> Right -> Root)"""\n        result = []\n        self._postorder_recursive(self.root, result)\n        return result\n    \n    def _postorder_recursive(self, node: Optional[TreeNode], result: List[int]) -> None:\n        """Helper for postorder traversal"""\n        if node is not None:\n            self._postorder_recursive(node.left, result)\n            self._postorder_recursive(node.right, result)\n            result.append(node.val)\n    \n    def level_order_traversal(self) -> List[int]:\n        """\n        Perform level-order traversal (breadth-first).\n        Returns nodes level by level from left to right.\n        """\n        if self.root is None:\n            return []\n        \n        result = []\n        queue = deque([self.root])\n        \n        while queue:\n            node = queue.popleft()\n            result.append(node.val)\n            \n            if node.left:\n                queue.append(node.left)\n            if node.right:\n                queue.append(node.right)\n        \n        return result\n    \n    def is_empty(self) -> bool:\n        """Check if the tree is empty"""\n        return self.root is None\n    \n    def height(self) -> int:\n        """Calculate the height of the tree"""\n        return self._height_recursive(self.root)\n    \n    def _height_recursive(self, node: Optional[TreeNode]) -> int:\n        """Helper method to calculate height recursively"""\n        if node is None:\n            return -1  # Height of empty tree is -1\n        \n        left_height = self._height_recursive(node.left)\n        right_height = self._height_recursive(node.right)\n        \n        return 1 + max(left_height, right_height)\n    \n    def is_valid_bst(self) -> bool:\n        """Validate if the tree maintains BST property"""\n        return self._is_valid_bst_recursive(self.root, float('-inf'), float('inf'))\n    \n    def _is_valid_bst_recursive(self, node: Optional[TreeNode], min_val: float, max_val: float) -> bool:\n        """Helper method to validate BST property"""\n        if node is None:\n            return True\n        \n        if node.val <= min_val or node.val >= max_val:\n            return False\n        \n        return (self._is_valid_bst_recursive(node.left, min_val, node.val) and\n                self._is_valid_bst_recursive(node.right, node.val, max_val))\n    \n    def __str__(self) -> str:\n        """String representation showing inorder traversal"""\n        if self.is_empty():\n            return "Empty BST"\n        return f"BST: {self.inorder_traversal()}"\n\n\n# Example usage and testing\nif __name__ == "__main__":\n    # Create a new BST\n    bst = BinarySearchTree()\n    \n    # Test insertions\n    values = [50, 30, 70, 20, 40, 60, 80]\n    print("Inserting values:", values)\n    for val in values:\n        bst.insert(val)\n    \n    print(f"Tree: {bst}")\n    print(f"Height: {bst.height()}")\n    print(f"Is valid BST: {bst.is_valid_bst()}")\n    \n    # Test search\n    print(f"\\nSearch 40: {bst.search(40)}")\n    print(f"Search 25: {bst.search(25)}")\n    \n    # Test min/max\n    print(f"Min value: {bst.find_min()}")\n    print(f"Max value: {bst.find_max()}")\n    \n    # Test traversals\n    print(f"\\nInorder (sorted): {bst.inorder_traversal()}")\n    print(f"Preorder: {bst.preorder_traversal()}")\n    print(f"Postorder: {bst.postorder_traversal()}")\n    print(f"Level-order: {bst.level_order_traversal()}")\n    \n    # Test deletion\n    print(f"\\nDeleting 30...")\n    bst.delete(30)\n    print(f"After deletion: {bst.inorder_traversal()}")\n    \n    print(f"Deleting 50 (root)...")\n    bst.delete(50)\n    print(f"After deletion: {bst.inorder_traversal()}")\n```\n\n## How to Use:\n\n1. **Basic Operations**:\n   ```python\n   bst = BinarySearchTree()\n   bst.insert(10)\n   bst.insert(5)\n   bst.insert(15)\n   \n   print(bst.search(5))    # True\n   print(bst.search(20))   # False\n   \n   bst.delete(5)\n   ```\n\n2. **Traversals**:\n   ```python\n   # Get sorted values\n   sorted_values = bst.inorder_traversal()\n   \n   # Get level-by-level values\n   level_order = bst.level_order_traversal()\n   ```\n\n3. **Utility Methods**:\n   ```python\n   print(f"Tree height: {bst.height()}")\n   print(f"Min value: {bst.find_min()}")\n   print(f"Max value: {bst.find_max()}")\n   print(f"Is valid BST: {bst.is_valid_bst()}")\n   ```\n\n**Key Features**:\n- **Time Complexity**: O(log n) average case for insert/search/delete, O(n) worst case\n- **Space Complexity**: O(n) for storage, O(log n) average recursion depth\n- **Error Handling**: Gracefully handles edge cases like empty trees and duplicate values\n- **Type Hints**: Full type annotations for better code clarity\n- **Comprehensive Testing**: Example usage demonstrates all functionality\n\nThe implementation maintains the BST invariant and provides efficient operations with clean, readable code.	{}	2026-02-03 10:10:01.206906
