299	138	ai	I'll create a bash script to find files larger than 100MB with proper error handling and user-friendly output.\n\n## Approach\n- Use `find` command with size parameter (+100M)\n- Add error handling for permission issues\n- Provide clear output with file sizes\n- Include options for different search paths\n- Add progress indication for large filesystem searches\n\n## Complete Script\n\n```bash\n#!/bin/bash\n\n# find_large_files.sh - Find files larger than 100MB in the filesystem\n# Usage: ./find_large_files.sh [search_path] [size_threshold]\n\nset -euo pipefail  # Exit on error, undefined vars, pipe failures\n\n# Default values\nDEFAULT_SEARCH_PATH="/"\nDEFAULT_SIZE="100M"\nSCRIPT_NAME=$(basename "$0")\n\n# Color codes for output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m' # No Color\n\n# Function to display usage\nusage() {\n    echo "Usage: $SCRIPT_NAME [search_path] [size_threshold]"\n    echo ""\n    echo "Arguments:"\n    echo "  search_path     Directory to search (default: /)"\n    echo "  size_threshold  Minimum file size (default: 100M)"\n    echo ""\n    echo "Size format examples: 100M, 1G, 500K"\n    echo ""\n    echo "Examples:"\n    echo "  $SCRIPT_NAME                    # Search entire filesystem for files > 100MB"\n    echo "  $SCRIPT_NAME /home             # Search /home for files > 100MB"\n    echo "  $SCRIPT_NAME /var/log 50M      # Search /var/log for files > 50MB"\n    echo "  $SCRIPT_NAME . 1G              # Search current dir for files > 1GB"\n}\n\n# Function to validate size format\nvalidate_size() {\n    local size="$1"\n    if [[ ! "$size" =~ ^[0-9]+[KMG]?$ ]]; then\n        echo -e "${RED}Error: Invalid size format '$size'${NC}" >&2\n        echo "Valid formats: 100M, 1G, 500K, 1000 (bytes)" >&2\n        return 1\n    fi\n}\n\n# Function to convert human-readable size to bytes for display\nsize_to_bytes() {\n    local size="$1"\n    local number="${size%[KMG]}"\n    local unit="${size: -1}"\n    \n    case "$unit" in\n        K) echo $((number * 1024)) ;;\n        M) echo $((number * 1024 * 1024)) ;;\n        G) echo $((number * 1024 * 1024 * 1024)) ;;\n        *) echo "$number" ;;\n    esac\n}\n\n# Function to format bytes to human readable\nformat_bytes() {\n    local bytes=$1\n    local units=("B" "K" "M" "G" "T")\n    local unit=0\n    local size=$bytes\n    \n    while [[ $size -gt 1024 && $unit -lt 4 ]]; do\n        size=$((size / 1024))\n        ((unit++))\n    done\n    \n    printf "%.1f%s" "$size" "${units[$unit]}"\n}\n\n# Function to check if running as root\ncheck_permissions() {\n    if [[ $EUID -ne 0 ]]; then\n        echo -e "${YELLOW}Warning: Not running as root. Some files may be inaccessible.${NC}" >&2\n        echo -e "${YELLOW}Consider running with sudo for complete filesystem access.${NC}" >&2\n        echo ""\n    fi\n}\n\n# Main function to find large files\nfind_large_files() {\n    local search_path="$1"\n    local size_threshold="$2"\n    local temp_file\n    local file_count=0\n    local total_size=0\n    \n    # Create temporary file for results\n    temp_file=$(mktemp)\n    trap "rm -f '$temp_file'" EXIT\n    \n    echo -e "${BLUE}Searching for files larger than $size_threshold in: $search_path${NC}"\n    echo -e "${BLUE}Started at: $(date)${NC}"\n    echo ""\n    \n    # Find files and redirect errors to handle permission issues gracefully\n    find "$search_path" -type f -size "+$size_threshold" -exec ls -la {} \\; 2>/dev/null | \\\n    while read -r permissions links owner group size month day time_year filename; do\n        # Skip if this is a header line or empty\n        [[ "$permissions" =~ ^- ]] || continue\n        \n        # Format the output\n        printf "%-10s %s\\n" "$(format_bytes "$size")" "$filename"\n        \n        # Save to temp file for summary\n        echo "$size" >> "$temp_file"\n    done\n    \n    # Calculate summary if temp file has content\n    if [[ -s "$temp_file" ]]; then\n        file_count=$(wc -l < "$temp_file")\n        total_size=$(awk '{sum += $1} END {print sum}' "$temp_file")\n        \n        echo ""\n        echo -e "${GREEN}Summary:${NC}"\n        echo -e "${GREEN}Found $file_count files larger than $size_threshold${NC}"\n        echo -e "${GREEN}Total size: $(format_bytes "$total_size")${NC}"\n    else\n        echo -e "${YELLOW}No files larger than $size_threshold found in $search_path${NC}"\n    fi\n    \n    echo -e "${BLUE}Completed at: $(date)${NC}"\n}\n\n# Main script execution\nmain() {\n    # Parse command line arguments\n    local search_path="${1:-$DEFAULT_SEARCH_PATH}"\n    local size_threshold="${2:-$DEFAULT_SIZE}"\n    \n    # Handle help option\n    if [[ "${1:-}" == "-h" || "${1:-}" == "--help" ]]; then\n        usage\n        exit 0\n    fi\n    \n    # Validate inputs\n    if [[ ! -d "$search_path" ]]; then\n        echo -e "${RED}Error: Directory '$search_path' does not exist${NC}" >&2\n        exit 1\n    fi\n    \n    if ! validate_size "$size_threshold"; then\n        exit 1\n    fi\n    \n    # Check permissions and warn user\n    check_permissions\n    \n    # Execute the search\n    find_large_files "$search_path" "$size_threshold"\n}\n\n# Run main function with all arguments\nmain "$@"\n```\n\n## How to Use\n\n1. **Make the script executable:**\n   ```bash\n   chmod +x find_large_files.sh\n   ```\n\n2. **Basic usage examples:**\n   ```bash\n   # Search entire filesystem for files > 100MB (requires sudo for full access)\n   sudo ./find_large_files.sh\n   \n   # Search home directory for files > 100MB\n   ./find_large_files.sh /home\n   \n   # Search /var/log for files > 50MB\n   ./find_large_files.sh /var/log 50M\n   \n   # Search current directory for files > 1GB\n   ./find_large_files.sh . 1G\n   \n   # Show help\n   ./find_large_files.sh --help\n   ```\n\n## Key Features\n\n- **Error handling**: Gracefully handles permission denied errors\n- **Flexible parameters**: Customizable search path and size threshold\n- **Human-readable output**: Shows file sizes in appropriate units (KB, MB, GB)\n- **Progress feedback**: Shows start/end times and summary statistics\n- **Permission warnings**: Alerts when not running as root\n- **Input validation**: Validates directory existence and size format\n- **Clean output**: Color-coded, well-formatted results\n\nThe script assumes you want to search readable files only and handles permission errors silently to avoid cluttering the output with error messages.	{}	2026-02-03 10:10:46.704495
